@using sv_90c56c6989be4c969ebe09f418a37668.Models

<div class="col">
    <div class="card h-100">
        <div class="card-header d-flex justify-content-between align-items-center">
            <strong>@ColumnName</strong>
            <span class="badge bg-secondary">@Tasks.Count</span>
        </div>
        <div class="card-body overflow-auto" style="max-height: 70vh;">
            @foreach (var task in Tasks)
            {
                <TaskCard Task="task"
                          ShowMoveLeft="HasLeftColumn"
                          ShowMoveRight="HasRightColumn"
                          OnMoveLeft="OnMoveLeft"
                          OnMoveRight="OnMoveRight" />
            }

            @if (_showForm)
            {
                <AddTaskForm ColumnStatus="@Status"
                             OnSave="HandleSave"
                             OnCancel="HideForm" />
            }
            else
            {
                <button class="btn btn-outline-primary btn-sm w-100 mt-2" @onclick="ShowForm">
                    + Add Task
                </button>
            }
        </div>
    </div>
</div>

@code {
    [Parameter, EditorRequired] public string ColumnName { get; set; } = default!;
    [Parameter, EditorRequired] public string Status { get; set; } = default!;
    [Parameter] public List<TaskItem> Tasks { get; set; } = new();
    [Parameter] public bool HasLeftColumn { get; set; }
    [Parameter] public bool HasRightColumn { get; set; }
    [Parameter] public EventCallback<int> OnMoveLeft { get; set; }
    [Parameter] public EventCallback<int> OnMoveRight { get; set; }
    [Parameter] public EventCallback<(string Title, string Assignee, string Priority, DateTime DueDate)> OnAddTask { get; set; }

    private bool _showForm;

    private void ShowForm() => _showForm = true;

    private async Task HideForm() => _showForm = false;

    private async Task HandleSave((string Title, string Assignee, string Priority, DateTime DueDate) formData)
    {
        await OnAddTask.InvokeAsync(formData);
        _showForm = false;
    }
}

