@page "/board"
@rendermode InteractiveServer
@using sv_90c56c6989be4c969ebe09f418a37668.Models
@using sv_90c56c6989be4c969ebe09f418a37668.Services
@inject ITaskService TaskService

<PageTitle>Kanban Board</PageTitle>

<h3 class="mb-3">Kanban Board</h3>

@if (_loading)
{
    <div class="d-flex justify-content-center my-5">
        <div class="spinner-border" role="status">
            <span class="visually-hidden">Loading...</span>
        </div>
    </div>
}
else if (_error is not null)
{
    <div class="alert alert-danger">
        <strong>Error loading tasks:</strong> @_error
        <button class="btn btn-outline-danger btn-sm ms-2" @onclick="LoadTasks">Retry</button>
    </div>
}
else
{
    <BoardStats TotalCount="_filteredTasks.Count"
                TodoCount="GetColumnTasks(TodoStatus).Count"
                InProgressCount="GetColumnTasks(InProgressStatus).Count"
                DoneCount="GetColumnTasks(DoneStatus).Count"
                OverdueCount="_filteredTasks.Count(t => t.DueDate < DateTime.Today)" />

    <BoardSearchBar SearchText="@_searchText" OnSearchChanged="HandleSearchChanged" />

    <div class="row g-3">
        <BoardColumn ColumnName="To Do" Status="@TodoStatus"
                     Tasks="GetColumnTasks(TodoStatus)"
                     HasLeftColumn="false" HasRightColumn="true"
                     OnMoveRight="@(id => MoveTask(id, InProgressStatus))"
                     OnAddTask="@(data => AddTask(data, TodoStatus))" />

        <BoardColumn ColumnName="In Progress" Status="@InProgressStatus"
                     Tasks="GetColumnTasks(InProgressStatus)"
                     HasLeftColumn="true" HasRightColumn="true"
                     OnMoveLeft="@(id => MoveTask(id, TodoStatus))"
                     OnMoveRight="@(id => MoveTask(id, DoneStatus))"
                     OnAddTask="@(data => AddTask(data, InProgressStatus))" />

        <BoardColumn ColumnName="Done" Status="@DoneStatus"
                     Tasks="GetColumnTasks(DoneStatus)"
                     HasLeftColumn="true" HasRightColumn="false"
                     OnMoveLeft="@(id => MoveTask(id, InProgressStatus))"
                     OnAddTask="@(data => AddTask(data, DoneStatus))" />
    </div>
}

@code {
    private const string TodoStatus = "To Do";
    private const string InProgressStatus = "In Progress";
    private const string DoneStatus = "Done";

    private List<TaskItem> _allTasks = new();
    private List<TaskItem> _filteredTasks = new();
    private string _searchText = string.Empty;
    private bool _loading = true;
    private string? _error;

    protected override async Task OnInitializedAsync()
    {
        await LoadTasks();
    }

    private async Task LoadTasks()
    {
        _loading = true;
        _error = null;

        try
        {
            _allTasks = await TaskService.GetAllTasksAsync();
            ApplyFilter();
        }
        catch (Exception ex)
        {
            _error = ex.Message;
        }
        finally
        {
            _loading = false;
        }
    }

    private void HandleSearchChanged(string text)
    {
        _searchText = text;
        ApplyFilter();
    }

    private void ApplyFilter()
    {
        _filteredTasks = string.IsNullOrWhiteSpace(_searchText)
            ? _allTasks.ToList()
            : _allTasks.Where(t => t.Title.Contains(_searchText, StringComparison.OrdinalIgnoreCase)).ToList();
    }

    private List<TaskItem> GetColumnTasks(string status)
        => _filteredTasks.Where(t => t.Status == status).ToList();

    private async Task MoveTask(int taskId, string newStatus)
    {
        try
        {
            await TaskService.UpdateTaskStatusAsync(taskId, newStatus);

            var task = _allTasks.FirstOrDefault(t => t.Id == taskId);
            if (task is not null)
            {
                var index = _allTasks.IndexOf(task);
                _allTasks[index] = task with { Status = newStatus };
                ApplyFilter();
            }
        }
        catch (Exception ex)
        {
            _error = ex.Message;
        }
    }

    private async Task AddTask((string Title, string Assignee, string Priority, DateTime DueDate) data, string status)
    {
        try
        {
            var newTask = await TaskService.CreateTaskAsync(data.Title, data.Assignee, data.Priority, data.DueDate);
            // The service returns the task; ensure it has the correct status column
            var taskWithStatus = newTask with { Status = status };
            _allTasks.Add(taskWithStatus);
            ApplyFilter();
        }
        catch (Exception ex)
        {
            _error = ex.Message;
        }
    }
}

